import { Component, OnInit } from '@angular/core';
import { AuditoriaService, LogEntrada } from '../../services/auditoria.service';

@Component({
  selector: 'app-auditoria',
  templateUrl: './auditoria.component.html',
  styleUrls: ['./auditoria.component.css']
})
export class AuditoriaComponent implements OnInit {
  logs: LogEntrada[] = [];
  filtroTipo: string = '';
  paginaAtual = 1;
  registrosPorPagina = 20;
  totalPaginas = 0;

  constructor(private auditoriaService: AuditoriaService) { }

  ngOnInit(): void {
    this.carregarLogs();
  }

  carregarLogs(): void {
    this.logs = this.auditoriaService.obterLogs();
    this.calcularPaginacao();
  }

  get logsFiltrados(): LogEntrada[] {
    let filtrados = this.logs;

    if (this.filtroTipo && this.filtroTipo !== '') {
      filtrados = filtrados.filter(log => log.tipo === this.filtroTipo);
    }

    // Paginação
    this.totalPaginas = Math.ceil(filtrados.length / this.registrosPorPagina);
    if (this.paginaAtual > this.totalPaginas && this.totalPaginas > 0) {
      this.paginaAtual = this.totalPaginas;
    }
    const inicio = (this.paginaAtual - 1) * this.registrosPorPagina;
    const fim = inicio + this.registrosPorPagina;

    return filtrados.slice(inicio, fim);
  }

  calcularPaginacao(): void {
    this.totalPaginas = Math.ceil(this.logs.length / this.registrosPorPagina);
  }

  obterCorTipo(tipo: string): string {
    switch (tipo) {
      case 'criar':
        return '#28a745';
      case 'atualizar':
        return '#17a2b8';
      case 'deletar':
        return '#dc3545';
      case 'imprimir':
        return '#007bff';
      default:
        return '#6c757d';
    }
  }

  obterEmojiTipo(tipo: string): string {
    switch (tipo) {
      case 'criar':
        return '➕';
      case 'atualizar':
        return '✏️';
      case 'deletar':
        return '🗑️';
      case 'imprimir':
        return '🖨️';
      default:
        return '📝';
    }
  }

  irParaPagina(pagina: number): void {
    if (pagina >= 1 && pagina <= this.totalPaginas) {
      this.paginaAtual = pagina;
    }
  }

  limparLogs(): void {
    if (confirm('Tem certeza que deseja limpar todo o histórico de auditoria?')) {
      this.auditoriaService.limparLogs();
      this.carregarLogs();
    }
  }
}
<div class="container">
  <h1>🔍 Auditoria - Histórico de Operações</h1>

  <div class="filters-container">
    <div class="filter-group">
      <label>Tipo de Operação:</label>
      <select [(ngModel)]="filtroTipo" (change)="paginaAtual = 1" class="filter-input">
        <option value="">Todas</option>
        <option value="criar">➕ Criar</option>
        <option value="atualizar">✏️ Atualizar</option>
        <option value="deletar">🗑️ Deletar</option>
        <option value="imprimir">🖨️ Imprimir</option>
        <option value="outro">📝 Outro</option>
      </select>
    </div>

    <button (click)="limparLogs()" class="btn btn-danger" *ngIf="logs.length > 0">
      🗑️ Limpar Histórico
    </button>
  </div>

  <div *ngIf="logsFiltrados.length > 0" class="logs-container">
    <table class="table">
      <thead>
        <tr>
          <th>Tipo</th>
          <th>Operação</th>
          <th>Descrição</th>
          <th>Data/Hora</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let log of logsFiltrados" [class.log-row]="true">
          <td>
            <span class="badge" [style.backgroundColor]="obterCorTipo(log.tipo)">
              {{ obterEmojiTipo(log.tipo) }} {{ log.tipo }}
            </span>
          </td>
          <td class="operacao">{{ log.operacao }}</td>
          <td class="descricao">{{ log.descricao }}</td>
          <td class="timestamp">{{ log.timestamp | date: 'dd/MM/yyyy HH:mm:ss' }}</td>
        </tr>
      </tbody>
    </table>

    <!-- Paginação -->
    <div class="pagination" *ngIf="totalPaginas > 1">
      <button (click)="irParaPagina(paginaAtual - 1)" class="btn btn-small btn-secondary" [disabled]="paginaAtual === 1">
        ← Anterior
      </button>
      
      <span class="pagination-info">
        Página {{ paginaAtual }} de {{ totalPaginas }}
      </span>
      
      <button (click)="irParaPagina(paginaAtual + 1)" class="btn btn-small btn-secondary" [disabled]="paginaAtual === totalPaginas">
        Próxima →
      </button>
    </div>
  </div>

  <div *ngIf="logsFiltrados.length === 0" class="empty-message">
    Nenhum registro de auditoria encontrado.
  </div>
</div>
